class Solution:
    def bestRotation(self, nums: List[int]) -> int:
        n = len(nums)
        score = sum(1 for j in range(1, n) if nums[j] <= nums[0])
        best = score; ans = 0
        for i in range(1, n):
            if nums[i] > nums[0]: score -= 1
            if nums[n - i] <= nums[0]: score += 1
            if score > best:
                best = score; ans = i
        return ans

