class Solution {
public:
    int bestRotation(vector<int>& a) {
        int n=a.size(), score=0;
        for(int j=1;j<n;j++) if(a[j]<=a[0]) score++;
        int best=score, ans=0;
        for(int i=1;i<n;i++){
            if(a[i]>a[0]) score--;
            if(a[n-i]<=a[0]) score++;
            if(score>best){ best=score; ans=i; }
        }
        return ans;
    }
};

